export default function HomePage({ mode }) {
    const navigate = useNavigate()
    const dispatch = useDispatch()
    const { state } = useLocation()
    const RegisterSchema = Yup.object().shape({
        firstName: Yup.string().required('First Name is required'),
        lastName: Yup.string().required('Last Name is required'),
        dob: Yup.string().required('Birthday is required'),
        gender: Yup.string(),
    })
    let userData = useSelector((s) => s.Onboarding)
    const formik = useFormik({
        initialValues: {
            firstName: userData.name?.split(' ')?.[0],
            lastName: userData.name.split(' ')?.[1],
            dob: new Date(),
        },
        validationSchema: RegisterSchema,
        onSubmit: async (values, { setErrors, setSubmitting }) => {
            dispatch(
                updateOnboarding({
                    name: values.firstName + ' ' + values.lastName,
                    DOB: values.dob,
                })
            )
            navigate(
                `/onboarding/${
                    mode == 'client' ? 'client/client-info' : 'profile-pic'
                }`,
                { state }
            )
        },
    })
    console.log(state)
    const {
        errors,
        touched,
        handleSubmit,
        isSubmitting,
        getFieldProps,
        setFieldValue,
        values,
    } = formik
    return (
        <Page title=" Simplified Online Fitness Training ">
            <FormikProvider value={formik}>
                <Form autoComplete="off" noValidate onSubmit={handleSubmit}>
                    <Container>
                        <Header
                            title={'Create profile'}
                            onClose={() => navigate('/', { state })}
                        />
                        <Content
                            display={'flex'}
                            height={'100%'}
                            flexDirection={'column'}
                            alignItems={'center'}
                            flexGrow={'1'}
                            px={2}
                        >
                            <Box
                                display={'flex'}
                                justifyContent="center"
                                alignItems={'center'}
                                mt={4}
                            >
                                <img src={Logo} height={46} />
                            </Box>
                            <Typography
                                variant="h2"
                                align="center"
                                sx={{ my: 4 }}
                            >
                                Personal information
                            </Typography>

                            <Stack spacing={2} sx={{ width: '100%' }}>
                                <TextField
                                    fullWidth
                                    clabel={
                                        <Typography variant="subtitle1">
                                            First name
                                            {/* <Typography component={"span"} color={"error"}>
                        *
                      </Typography> */}
                                        </Typography>
                                    }
                                    {...getFieldProps('firstName')}
                                    error={Boolean(
                                        touched.firstName && errors.firstName
                                    )}
                                    helperText={
                                        touched.firstName && errors.firstName
                                    }
                                />

                                <TextField
                                    fullWidth
                                    clabel={
                                        <Typography variant="subtitle1">
                                            Last name
                                            {/* <Typography component={"span"} color={"error"}>
                        *
                      </Typography> */}
                                        </Typography>
                                    }
                                    {...getFieldProps('lastName')}
                                    error={Boolean(
                                        touched.lastName && errors.lastName
                                    )}
                                    helperText={
                                        touched.lastName && errors.lastName
                                    }
                                />
                                <Box>
                                    <Typography
                                        variant="subtitle1"
                                        color="text.primary"
                                    >
                                        Gender
                                    </Typography>
                                    <RadioGroup
                                        {...getFieldProps('gender')}
                                        color={'primary.main'}
                                    >
                                        <Stack
                                            direction={'row'}
                                            spacing={2}
                                            alignItems="center"
                                        >
                                            <Stack
                                                direction={'row'}
                                                alignItems="center"
                                            >
                                                <Radio
                                                    color="primary"
                                                    value="female"
                                                />{' '}
                                                <Typography
                                                    variant="subtitle1"
                                                    color="text.secondary"
                                                >
                                                    Female
                                                </Typography>
                                            </Stack>
                                            <Stack
                                                direction={'row'}
                                                alignItems="center"
                                            >
                                                <Radio
                                                    color="primary"
                                                    value="male"
                                                />{' '}
                                                <Typography
                                                    variant="subtitle1"
                                                    color="text.secondary"
                                                >
                                                    Male
                                                </Typography>
                                            </Stack>
                                        </Stack>
                                    </RadioGroup>
                                </Box>
                                <Grid container>
                                    <Grid item xs={12} sx={{ mb: 1 }}>
                                        <Typography variant="subtitle1">
                                            Birthday
                                            {/* <Typography component={"span"} color={"error"}>
                        *
                      </Typography> */}
                                        </Typography>
                                    </Grid>
                                    <Grid item xs={4} sx={{ pr: 1 }}>
                                        <YearPicker
                                            defaultValue={'Year'}
                                            start={1950} // default is 1900
                                            end={2023} // default is current year
                                            reverse // default is ASCENDING
                                            required={true} // default is false
                                            // default is false
                                            // mandatory
                                            onChange={(year) => {
                                                // mandatory

                                                if (!year) return
                                                setFieldValue(
                                                    'dob',
                                                    new Date(
                                                        year,
                                                        values.dob.getMonth(),
                                                        values.dob.getDate()
                                                    )
                                                )
                                            }}
                                            id={'year'}
                                            name={'year'}
                                            classes={'dropdown-year'}
                                            style={{ width: '100%' }}
                                        />
                                    </Grid>
                                    <Grid item xs={4} sx={{ pr: 1 }}>
                                        <MonthPicker
                                            defaultValue={'Month'}
                                            // to get months as numbers
                                            short // default is full name
                                            // default is Titlecase
                                            endYearGiven // mandatory if end={} is given in YearPicker
                                            year={values.dob.getFullYear()} // mandatory
                                            required={true} // default is false
                                            // default is false

                                            classes={'dropdown-month'}
                                            onChange={(month) => {
                                                // mandatory
                                                if (!month) return
                                                setFieldValue(
                                                    'dob',
                                                    new Date(
                                                        values.dob.getFullYear(),
                                                        month,
                                                        values.dob.getDate()
                                                    )
                                                )
                                            }}
                                            id={'month'}
                                            name={'month'}
                                            optionClasses={'option classes'}
                                        />
                                    </Grid>
                                    <Grid item xs={4}>
                                        <DayPicker
                                            defaultValue={'Day'}
                                            year={values.dob.getFullYear()} // mandatory
                                            month={values.dob.getMonth()} // mandatory
                                            endYearGiven // mandatory if end={} is given in YearPicker
                                            required={true} // default is false
                                            // default is false

                                            onChange={(day) => {
                                                if (!day) return
                                                setFieldValue(
                                                    'dob',
                                                    new Date(
                                                        values.dob.getFullYear(),
                                                        values.dob.getMonth(),
                                                        day
                                                    )
                                                )
                                            }}
                                            id={'day'}
                                            classes={'dropdown-day'}
                                            name={'day'}
                                            //classes={"classes"}
                                            //optionClasses={"option classes"}
                                        />
                                    </Grid>
                                </Grid>
                                {/* <LocalizationProvider dateAdapter={AdapterDateFns}>
                  <DesktopDatePicker
                    // label="For mobile"
                    disableOpenPicker
                    {...getFieldProps("dob")}
                    inputFormat="dd/MM/yyyy"
                    error={Boolean(touched.dob && errors.dob)}
                    helperText={touched.dob && errors.dob}
                    onChange={(newValue) => {
                      setFieldValue("dob", newValue);
                    }}
                    renderInput={(params) => (
                      <TextField
                        {...params}
                        fullWidth
                        placeholder=""
                        clabel={
                          <Typography variant="subtitle1">
                            Your Birthday
                          
                          </Typography>
                        }
                      />
                    )}
                  />
                </LocalizationProvider> */}
                                <br />
                            </Stack>
                        </Content>
                        <FooterBase>
                            <Footer next back backClick={() => navigate(-1)} />
                        </FooterBase>
                    </Container>
                </Form>
            </FormikProvider>
        </Page>
    )
}
